import numpy as np
from utils import get_bler, bler_2_mcs

def mcs_selection(is_nack_hist: np.ndarray,
                  mcs_ackned_hist: np.ndarray,
                  bler_target: float) -> int:
    """Select an MCS index for the next transmission using empirical BLER estimation.
    """

    if len(is_nack_hist) == 0:
        return 0

    unique_mcs = np.unique(mcs_ackned_hist)
    empirical_blers = {}

    for mcs in unique_mcs:
        mask = (mcs_ackned_hist == mcs)
        nacks = np.sum(is_nack_hist[mask])
        total = np.sum(mask)
        empirical_blers[mcs] = nacks / total

    mcs_list = sorted(list(empirical_blers.keys()))
    bler_list = [empirical_blers[m] for m in mcs_list]
    mcs_arr = np.array(mcs_list)
    bler_arr = np.array(bler_list)

    # 1. Interpolated MCS Estimate
    mcs_interp_est = 0
    if len(mcs_arr) >= 2:
        best_mcs_interp = 0
        for m in range(32):
            val = np.interp(m, mcs_arr, bler_arr)
            if val <= bler_target:
                best_mcs_interp = m
            else:
                break
        mcs_interp_est = best_mcs_interp

    # 2. SINR Estimation via Least-Squares
    mcs_sinr_est = 0
    if len(mcs_arr) >= 1:
        sinr_candidates = np.linspace(-15, 35, 501) 
        best_sinr = -15
        min_error = float('inf')

        for s in sinr_candidates:
            current_bler_vec = get_bler(s)
            error = np.sum((current_bler_vec[mcs_arr] - bler_arr)**2)
            if error < min_error:
                min_error = error
                best_sinr = s

        # Apply a safety margin to the estimated SINR to ensure BLER <= target
        # A margin of 1.0 dB is often a good balance.
        safe_sinr = best_sinr - 1.0
        bler_at_sinr = get_bler(safe_sinr)
        mcs_sinr_est = bler_2_mcs(bler_at_sinr, bler_target)

    # 3. Combine estimates
    # If history is short, use the more conservative of the two.
    # If history is long, use the SINR-based one (which already has a safety margin).

    if len(is_nack_hist) < 30:
        if len(mcs_arr) < 2:
            # If we only have one MCS, use the SINR estimate with an even larger margin
            return int(max(0, mcs_sinr_est - 1))
        else:
            return int(max(0, min(mcs_interp_est, mcs_sinr_est)))
    else:
        return int(max(0, mcs_sinr_est))

