import numpy as np
from utils import get_bler, bler_2_mcs

def mcs_selection(is_nack_hist: np.ndarray,
                  mcs_ackned_hist: np.ndarray,
                  bler_target: float) -> int:
    """Select an MCS index for the next transmission using an adaptive-alpha MLE SINR estimator."""
    try:
        # Handle empty history
        n = len(is_nack_hist)
        if n == 0:
            return int(bler_2_mcs(get_bler(14.5), bler_target))

        # SINR grid from -10 to 40 dB
        sinr_grid = np.linspace(-10, 40, 101)

        # Determine alpha based on windows
        alpha = 0.80 # Default

        if n >= 20:
            window1 = is_nack_hist[-10:]
            window2 = is_nack_hist[-20:-10]

            bler1 = np.mean(window1)
            bler2 = np.mean(window2)

            if abs(bler1 - bler2) > 0.15:
                alpha = 0.95
            else:
                alpha = 0.80
        else:
            alpha = 0.80

        # MLE Estimation
        dist = np.arange(n)[::-1]
        w = alpha ** dist

        ll_grid = np.zeros_like(sinr_grid)

        for i, sinr in enumerate(sinr_grid):
            bler_at_sinr = get_bler(sinr)
            bler_at_sinr = np.clip(bler_at_sinr, 1e-10, 1 - 1e-10)

            # Get the BLERs for the MCSs used in the history
            history_blers = bler_at_sinr[mcs_ackned_hist]

            # log_probs: log(p) if nack == 1, else log(1-p)
            log_probs = np.where(is_nack_hist == 1, np.log(history_blers), np.log(1.0 - history_blers))

            ll_grid[i] = np.sum(w * log_probs)

        # Find best SINR
        if np.all(np.isnan(ll_grid)) or np.all(np.isinf(ll_grid)):
            best_sinr = 14.5
        else:
            best_sinr = sinr_grid[np.argmax(ll_grid)]

        # Refined adaptive margin
        # Recent BLER is computed over last 20 transmissions.
        recent_n = min(n, 20)
        recent_bler = np.mean(is_nack_hist[-recent_n:])

        if recent_bler < 0.5 * bler_target:
            margin = 0.3
        elif 0.5 * bler_target <= recent_bler <= 0.8 * bler_target:
            margin = 0.5
        elif 0.8 * bler_target < recent_bler <= bler_target:
            margin = 1.0
        else: # recent_bler > bler_target
            margin = 1.8

        target_sinr = best_sinr - margin
        bler_vals = get_bler(target_sinr)
        return int(bler_2_mcs(bler_vals, bler_target))

    except Exception:
        try:
            return int(bler_2_mcs(get_bler(14.5), bler_target))
        except:
            return 0

