        n = len(is_nack_hist)
        if n == 0:
            return int(bler_2_mcs(get_bler(15.0), bler_target))

        sinr_grid = np.linspace(-10, 40, 101)

        # MLE with alpha=0.85 for full history
        def compute_mle(history_nack, history_mcs, alpha_val):
            m = len(history_nack)
            if m == 0:
                return None
            dist = np.arange(m)[::-1]
            w = alpha_val ** dist
            ll_grid = np.zeros_like(sinr_grid)
            for i, sinr in enumerate(sinr_grid):
                bler_at_sinr = get_bler(sinr)
                bler_at_sinr = np.clip(bler_at_sinr, 1e-10, 1 - 1e-10)
                history_blers = bler_at_sinr[history_mcs]
                log_probs = np.where(history_nack == 1, np.log(history_blers), np.log(1.0 - history_blers))
                ll_grid[i] = np.sum(w * log_probs)
            return sinr_grid[np.argmax(ll_grid)]

        # Full history MLE
        full_mle = compute_mle(is_nack_hist, mcs_ackned_hist, 0.85)

        # Recent history MLE (last 10 samples)
        if n >= 10:
            recent_mle = compute_mle(is_nack_hist[-10:], mcs_ackned_hist[-10:], 0.90)
        else:
            recent_mle = None

        # Combine estimates
        if n >= 15 and recent_mle is not None:
            final_sinr = 0.7 * recent_mle + 0.3 * full_mle
        else:
            final_sinr = full_mle if full_mle is not None else 15.0

        # Apply safety margin
        # We are failing BLER. We need to be much more conservative.
        # Instead of a fixed margin, let's adjust based on recent performance.

        current_bler = np.mean(is_nack_hist)
        safety_margin = 0.5
        if current_bler > bler_target:
            safety_margin = 4.0
        elif current_bler > bler_target * 0.8:
            safety_margin = 2.0

        target_sinr = final_sinr - safety_margin
        bler_vals = get_bler(target_sinr)
        return int(bler_2_mcs(bler_vals, bler_target))

    except Exception:
        try:
            return int(bler_2_mcs(get_bler(14.5), bler_target))
        except:
            return 0

