import numpy as np
from utils import get_bler, bler_2_mcs

def mcs_selection(is_nack_hist: np.ndarray,
                  mcs_ackned_hist: np.ndarray,
                  bler_target: float) -> int:
    """Select an MCS index for the next transmission using a sliding-window MLE SINR estimator."""
    try:
        n = len(is_nack_hist)
        if n == 0:
            return int(bler_2_mcs(get_bler(15.0), bler_target))

        sinr_grid = np.linspace(-10, 40, 101)

        def get_mle(indices, alpha):
            if len(indices) == 0:
                return None

            sub_nack = is_nack_hist[indices]
            sub_mcs = mcs_ackned_hist[indices]

            sub_n = len(sub_nack)
            dist = np.arange(sub_n)[::-1]
            w = alpha ** dist

            ll_grid = np.zeros_like(sinr_grid)
            for i, sinr in enumerate(sinr_grid):
                bler_at_sinr = get_bler(sinr)
                bler_at_sinr = np.clip(bler_at_sinr, 1e-10, 1 - 1e-10)
                history_blers = bler_at_sinr[sub_mcs]
                log_probs = np.where(sub_nack == 1, np.log(history_blers), np.log(1.0 - history_blers))
                ll_grid[i] = np.sum(w * log_probs)

            return sinr_grid[np.argmax(ll_grid)]

        estimates = []
        weights = []

        # Window A: last 5 samples
        idx_a = np.arange(max(0, n-5), n)
        if len(idx_a) > 0:
            est_a = get_mle(idx_a, 0.95)
            if est_a is not None:
                estimates.append(est_a)
                weights.append(min(len(idx_a), 1))

        # Window B: last 10-30 samples. 
        # Let's try Window B as the window of the last 30 samples.
        idx_b = np.arange(max(0, n-30), n)
        if len(idx_b) > 0:
            est_b = get_mle(idx_b, 0.85)
            if est_b is not None:
                estimates.append(est_b)
                weights.append(min(len(idx_b), 10))

        # Window C: all samples
        idx_c = np.arange(n)
        if len(idx_c) > 0:
            est_c = get_mle(idx_c, 0.80)
            if est_c is not None:
                estimates.append(est_c)
                weights.append(min(len(idx_c), 50))

        if not estimates:
            return int(bler_2_mcs(get_bler(15.0), bler_target))

        combined_sinr = np.average(estimates, weights=weights)
        target_sinr = combined_sinr - 0.5
        bler_vals = get_bler(target_sinr)
        return int(bler_2_mcs(bler_vals, bler_target))

    except Exception:
        try:
            return int(bler_2_mcs(get_bler(15.0 - 0.5), bler_target))
        except:
            return 0

