def mcs_selection(is_nack_hist: np.ndarray,
                  mcs_ackned_hist: np.ndarray,
                  bler_target: float) -> int:
    """Select an MCS index for the next transmission using a Thompson Sampling / Bayesian bandit approach.

    Treats each MCS index as a Bernoulli bandit arm where success = ACK, failure = NACK.
    """
    try:
        # Number of samples in history
        n = len(is_nack_hist)

        # If no history, use the fallback
        if n == 0:
            return int(bler_2_mcs(get_bler(14.5), bler_target))

        # Find the actual max MCS index in the history to avoid assuming 31
        # But we should also consider that we might want to try higher MCS.
        # Let's check the history for the max MCS and then allow some headroom.
        if n > 0:
            max_seen_mcs = int(np.max(mcs_ackned_hist))
            max_mcs_possible = max_seen_mcs + 5 # Allow some exploration above seen
            if max_mcs_possible > 31:
                max_mcs_possible = 31
        else:
            max_mcs_possible = 31

        # alpha_i = 1 + (ACK count for that MCS)
        # beta_i = 1 + (NACK count for that MCS)

        alphas = np.ones(max_mcs_possible + 1)
        betas = np.ones(max_mcs_possible + 1)
        counts = np.zeros(max_mcs_possible + 1)

        for i in range(n):
            mcs = int(mcs_ackned_hist[i])
            if 0 <= mcs <= max_mcs_possible:
                is_nack = is_nack_hist[i]
                counts[mcs] += 1
                if is_nack == 1:  # NACK
                    betas[mcs] += 1
                else:             # ACK
                    alphas[mcs] += 1

        # Determine the best MCS based on the assigned approach:
        # "Select the highest MCS index where the empirical BLER (1 - alpha_i/(alpha_i+beta_i)) <= bler_target, 
        # with a minimum of 2 samples required before trusting that MCS's estimate; 
        # for untested MCS indices assume BLER=0.5."

        # The prompt says: alpha_i = 1 + (ACK count), beta_i = 1 + (NACK count)
        # expected success rate = alpha_i / (alpha_i + beta_i)
        # empirical BLER = 1 - alpha_i / (alpha_i + beta_i)

        best_mcs = -1

        # We iterate from highest MCS to lowest to find the "highest MCS index"
        for mcs in range(max_mcs_possible, -1, -1):
            if counts[mcs] >= 2:
                # empirical BLER = 1 - alpha_i/(alpha_i+beta_i)
                empirical_bler = 1.0 - (alphas[mcs] / (alphas[mcs] + betas[mcs]))

                if empirical_bler <= bler_target:
                    best_mcs = mcs
                    break
            else:
                # Untested or < 2 samples: assume BLER = 0.5
                if 0.5 <= bler_target:
                    best_mcs = mcs
                    break

        if best_mcs != -1:
            return int(best_mcs)
        else:
            # If no MCS satisfies the constraint, fallback
            return int(bler_2_mcs(get_bler(14.5), bler_target))

    except Exception:
        try:
            return int(bler_2_mcs(get_bler(14.5), bler_target))
        except:
            return 0

