            for i, sinr in enumerate(sinr_grid):
                bler_at_sinr = get_bler(sinr)
                bler_at_sinr = np.clip(bler_at_sinr, 1e-10, 1 - 1e-10)
                history_blers = bler_at_sinr[mcs_ackned_hist]

                # Vectorized log-likelihood calculation
                log_probs = np.where(is_nack_hist == 1, np.log(history_blers), np.log(1.0 - history_blers))
                ll_grid[i] = np.sum(w * log_probs)

            if np.all(np.isnan(ll_grid)) or np.all(np.isinf(ll_grid)):
                sinr_estimates.append(15.0)
            else:
                sinr_estimates.append(sinr_grid[np.argmax(ll_grid)])

        best_sinr = np.median(sinr_estimates)

        # 3. Determine safety margin
        num_nacks = np.sum(is_nack_hist)
        if num_nacks == n:
            safety_margin = 1.5
        elif num_nacks == 0:
            safety_margin = 0.25
        else:
            current_bler = np.mean(is_nack_hist)
            if current_bler > bler_target:
                safety_margin = 1.5
            else:
                # Assigned approach: three-tier normal margin
                # - 0.45 dB when history < 15
                # - 0.35 dB when history >= 15 and recent BLER < bler_target
                # - 0.25 dB when history >= 30 and recent BLER < 0.5*bler_target

                # Using a smaller window for 'recent' to be more responsive
                recent_n = min(15, n) 
                recent_bler = np.mean(is_nack_hist[-recent_n:])

                if n >= 30 and recent_bler < 0.5 * bler_target:
                    safety_margin = 0.25
                elif n >= 15 and recent_bler < bler_target:
                    safety_margin = 0.35
                else:
                    safety_margin = 0.45

        target_sinr = best_sinr - safety_margin
        bler_vals = get_bler(target_sinr)
        return int(bler_2_mcs(bler_vals, bler_target))

    except Exception:
        try:
            return int(bler_2_mcs(get_bler(14.5), bler_target))
        except:
            return 0
